def utc_now_compact() -> str:
    return datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%SZ")


def sha256_json(payload: Mapping[str, Any]) -> str:
    blob = json.dumps(payload, sort_keys=True, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
    return hashlib.sha256(blob).hexdigest()


def _iter_json_reports(root: Path) -> list[Path]:
    if not root.exists():
        return []
    return sorted(root.glob("*.json"), key=lambda p: (p.stat().st_mtime_ns, p.name), reverse=True)


def _is_ready_source(payload: Mapping[str, Any], patch_id: str, patch_version: str) -> bool:
    return (
        payload.get("ok") is True
        and payload.get("status") == "READY"
        and payload.get("patch_id") == patch_id
        and payload.get("patch_version") == patch_version
        and int(payload.get("final_safety_violation_count", 0) or 0) == 0
        and payload.get("runtime_start_command_executed") is False
        and payload.get("runtime_start_command_execution_performed") is False
        and payload.get("runtime_start_performed") is False
        and payload.get("runtime_process_started") is False
        and payload.get("paper_runtime_start_performed") is False
        and payload.get("paper_order_submit_performed") is False
        and payload.get("network_order_submit_performed") is False
        and payload.get("approved_for_live_real") is False
        and payload.get("approved_for_exchange_submit") is False
        and payload.get("exchange_submit_performed") is False
    )


def _find_external_source_report(reports_dir: str | Path, patch_id: str, patch_version: str) -> tuple[dict[str, Any] | None, Path | None]:
    root = Path(reports_dir)
    for path in _iter_json_reports(root):
        try:
            payload = json.loads(path.read_text(encoding="utf-8"))
        except Exception:
            continue
        if _is_ready_source(payload, patch_id, patch_version):
            return payload, path
    return None, None


def _rules(spec: Mapping[str, Any]) -> list[dict[str, Any]]:
    return [{"rule_id": f"rule_{idx:02d}", "policy": str(text), "ready": True} for idx, text in enumerate(spec.get("rules", []), start=1)]


def _source_for_spec(spec: Mapping[str, Any], reports_dir: str | Path, stack: tuple[str, ...]) -> tuple[dict[str, Any] | None, Path | None, bool]:
    source_patch_id = str(spec["source_patch_id"])
    source_version = str(spec["source_version"])
    if source_patch_id in PHASE_BY_ID:
        if source_patch_id in stack:
            return None, None, False
        payload = evaluate_phase(source_patch_id, reports_dir=reports_dir, write_reports=False, _stack=stack + (source_patch_id,))
        return payload, None, _is_ready_source(payload, source_patch_id, source_version)
    payload, path = _find_external_source_report(reports_dir, source_patch_id, source_version)
    return payload, path, payload is not None


